mapper.select:
SELECT *
FROM attendance_record
WHERE schedule_id = #{scheduleId}
  AND student_id = #{studentId}
  AND attendance_date = #{attendanceDate}
LIMIT 1

mapper.update:
UPDATE attendance_record
SET status = #{status}
WHERE id = #{id}

mapper.select:
SELECT ar.attendance_date,
       ar.status,
       ci.course_name
FROM attendance_record ar
LEFT JOIN course_info ci ON ci.id = ar.course_id
WHERE ar.student_id = #{studentId}
  AND ar.attendance_date >= #{startDate}
  AND ar.attendance_date <= #{endDate}
ORDER BY ar.attendance_date ASC, ar.id ASC

SELECT ar.id, ar.course_id, ci.course_name, ar.class_id, cl.class_name, ar.student_id, su.real_name AS student_name, ar.attendance_date, ar.sign_in_time, ar.sign_out_time, ar.status FROM attendance_record ar LEFT JOIN course_info ci ON ci.id = ar.course_id LEFT JOIN class_info cl ON cl.id = ar.class_id LEFT JOIN sys_user su ON su.id = ar.student_id WHERE 1 = 1
AND ar.course_id = #{courseId}
AND ar.class_id = #{classId}
AND ar.attendance_date = #{attendanceDate}
AND ar.status = #{status}
ORDER BY ar.attendance_date DESC, ar.id DESC

SELECT ar.id, ar.course_id, ci.course_name, ar.class_id, cl.class_name, ar.student_id, su.real_name AS student_name, ar.attendance_date, ar.sign_in_time, ar.sign_out_time, ar.status FROM attendance_record ar LEFT JOIN course_info ci ON ci.id = ar.course_id LEFT JOIN class_info cl ON cl.id = ar.class_id LEFT JOIN sys_user su ON su.id = ar.student_id WHERE 1 = 1
AND ar.course_id = #{courseId}
AND ar.class_id = #{classId}
AND ar.attendance_date >= #{startDate}
AND ar.attendance_date <= #{endDate}
ORDER BY ar.attendance_date DESC, ar.id DESC

SELECT ar.id, ar.course_id, ci.course_name, ar.class_id, cl.class_name, ar.student_id, su.real_name AS student_name, ar.attendance_date, ar.sign_in_time, ar.sign_out_time, ar.status FROM attendance_record ar LEFT JOIN course_info ci ON ci.id = ar.course_id LEFT JOIN class_info cl ON cl.id = ar.class_id LEFT JOIN sys_user su ON su.id = ar.student_id WHERE ci.teacher_id = #{teacherId}
AND ar.course_id = #{courseId}
AND ar.class_id = #{classId}
AND ar.attendance_date = #{attendanceDate}
AND ar.status = #{status}
ORDER BY ar.attendance_date DESC, ar.id DESC
